const body = $input.first().json;
let messageData = {
  from: '',
  messageBody: '',
  messageId: '',
  phoneNumberId: '',
  timestamp: '',
  messageType: 'text'
};
try {
  const entry = body.entry?.[0];
  const changes = entry?.changes?.[0];
  const value = changes?.value;
  const message = value?.messages?.[0];
  messageData.from = message?.from || '';
  messageData.messageBody = message?.text?.body || message?.interactive?.button_reply?.title || message?.interactive?.list_reply?.title || '';
  messageData.messageId = message?.id || '';
  messageData.phoneNumberId = value?.metadata?.phone_number_id || process.env.WHATSAPP_PHONE_NUMBER_ID || '';
  messageData.timestamp = message?.timestamp || String(Date.now());
  messageData.messageType = message?.type || 'text';
} catch(e) {
  messageData.extractError = e.message;
}
return [{ json: messageData }];

const sessions = $getWorkflowStaticData('global');
const messageData = $('📊 Extract Message Data').first().json;
const from = messageData.from;
const doctorRows = $input.all().map(i => i.json);

if (!sessions.sessions) sessions.sessions = {};

if (!sessions.sessions[from]) {
  sessions.sessions[from] = {
    step: 'greeting',
    patientName: '',
    symptoms: '',
    preferredDate: '',
    preferredTime: '',
    selectedDoctor: null,
    appointmentConfirmed: false,
    lastUpdated: new Date().toISOString()
  };
}

const session = sessions.sessions[from];
const doctors = doctorRows.filter(d => d.doctor_name && d.doctor_name.trim() !== '');

sessions.sessions[from].lastUpdated = new Date().toISOString();

return [{ json: {
  ...messageData,
  session,
  doctors,
  allDoctors: doctors
}}];

