      "content": "{{ $json.messageBody }}"
    }
  ]
}

parameters.jsCode:
const aiRaw = $input.first().json;
const prevData = $('🗄️ Session Manager & Load Doctors').first().json;
const sessions = $getWorkflowStaticData('global');
const from = prevData.from;

let responseText = '';
try {
  responseText = aiRaw.choices?.[0]?.message?.content || aiRaw.message?.content || 'I am sorry, I could not process your request. Please try again.';
} catch(e) {
  responseText = 'Sorry, something went wrong. Please try again or call us directly.';
}

let session = sessions.sessions[from];
let displayText = responseText;

const nextStepMatch = responseText.match(/NEXT_STEP:(\w+)/);
const patientNameMatch = responseText.match(/PATIENT_NAME:([^\n]+)/);
const selectedDoctorMatch = responseText.match(/SELECTED_DOCTOR:([^\n]+)/);
const preferredDateMatch = responseText.match(/PREFERRED_DATE:([^\n]+)/);
const preferredTimeMatch = responseText.match(/PREFERRED_TIME:([^\n]+)/);

if (nextStepMatch) {
  session.step = nextStepMatch[1].trim();
  displayText = displayText.replace(/NEXT_STEP:\w+/, '').trim();
}
if (patientNameMatch) {
  session.patientName = patientNameMatch[1].trim();
  displayText = displayText.replace(/PATIENT_NAME:[^\n]+/, '').trim();
}
if (selectedDoctorMatch) {
  const docName = selectedDoctorMatch[1].trim();
  const matchedDoc = prevData.allDoctors.find(d => d.doctor_name && d.doctor_name.toLowerCase().includes(docName.toLowerCase()));
  if (matchedDoc) session.selectedDoctor = matchedDoc;
  displayText = displayText.replace(/SELECTED_DOCTOR:[^\n]+/, '').trim();
}
if (preferredDateMatch) {
  session.preferredDate = preferredDateMatch[1].trim();
  displayText = displayText.replace(/PREFERRED_DATE:[^\n]+/, '').trim();
}
if (preferredTimeMatch) {
  session.preferredTime = preferredTimeMatch[1].trim();
  displayText = displayText.replace(/PREFERRED_TIME:[^\n]+/, '').trim();
}

if (session.step === 'booking_complete' || session.step === 'done') {
  session.appointmentConfirmed = true;
}

displayText = displayText.replace(/\n{3,}/g, '\n\n').trim();

if (prevData.messageBody) {
  session.symptoms = prevData.messageBody;
}

sessions.sessions[from] = session;

const isBookingReady = (session.step === 'booking_complete' || session.step === 'done') && session.appointmentConfirmed && session.selectedDoctor;

return [{ json: {
  ...prevData,
  aiResponse: displayText,
  session,
  isBookingReady,
  appointmentPayload: isBookingReady ? {
    patient_name: session.patientName,
    phone: from,
    symptoms: session.symptoms,
    doctor_name: session.selectedDoctor?.doctor_name || '',
    doctor_email: session.selectedDoctor?.email || '',
    doctor_specialty: session.selectedDoctor?.specialty || '',
    doctor_timings: session.selectedDoctor?.timings || '',
    clinic_address: session.selectedDoctor?.clinic_address || '',
    appointment_date: session.preferredDate,
    appointment_time: session.preferredTime,
    booking_status: 'Confirmed',
    booked_at: new Date().toISOString()
  } : null
}}];

